#include <bits/stdc++.h>
using namespace std;
#define int long long
int a,b,ans=LLONG_MAX;
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>a>>b;
	for(int i=1; i<=2*b; i++) {
		int bb=abs(i-b),k=a/i;
		if(k<1){
			k=1;
		}
		int kk=k+1;
		ans=min(ans,bb+min(abs(a-k*i),abs(a-kk*i)));
	}
	cout<<ans;
	return 0;
}
